const CONFIG = {
  SPREADSHEET_ID: "1DUnHFzvd2GD-CsAGI7aeYD1yQnPwLSyk-cDcJIYLv5o",
  SHEET_NAME: "feedback_site"
};

const HEADERS = [
  "id_resposta",
  "data_hora",
  "nome",
  "bairro",
  "avaliacao",
  "mensagem",
  "aceite_uso_academico",
  "origem",
  "pagina_origem",
  "user_agent"
];

function getSpreadsheet() {
  return SpreadsheetApp.openById(CONFIG.SPREADSHEET_ID);
}

function setupPlanilhaFeedback() {
  const spreadsheet = getSpreadsheet();
  let sheet = spreadsheet.getSheetByName(CONFIG.SHEET_NAME);

  if (!sheet) {
    sheet = spreadsheet.insertSheet(CONFIG.SHEET_NAME);
  }

  const firstRow = sheet.getRange(1, 1, 1, HEADERS.length).getValues()[0];
  const hasHeaders = firstRow.some(value => String(value).trim() !== "");

  if (!hasHeaders) {
    sheet.getRange(1, 1, 1, HEADERS.length).setValues([HEADERS]);
  }

  sheet.setFrozenRows(1);

  sheet.getRange(1, 1, 1, HEADERS.length)
    .setFontWeight("bold")
    .setBackground("#dff3e6");

  sheet.autoResizeColumns(1, HEADERS.length);

  return ContentService
    .createTextOutput("Aba feedback_site configurada com sucesso.")
    .setMimeType(ContentService.MimeType.TEXT);
}

function doGet() {
  return jsonResponse({
    status: "online",
    message: "Web App de feedback ativo.",
    sheet_name: CONFIG.SHEET_NAME
  });
}

function doPost(e) {
  try {
    const params = e && e.parameter ? e.parameter : {};

    // Honeypot anti-spam: se preenchido, ignora o envio.
    if (sanitize(params.website, 200)) {
      return jsonResponse({
        status: "success",
        message: "Envio recebido."
      });
    }

    const nome = sanitize(params.nome, 120);
    const bairro = sanitize(params.bairro, 120);
    const avaliacao = sanitize(params.avaliacao, 30);
    const mensagem = sanitize(params.mensagem, 1000);
    const aceite = sanitize(params.aceite_uso_academico, 20);
    const origem = sanitize(params.origem, 80) || "site-github-pages";
    const paginaOrigem = sanitize(params.pagina_origem, 200);
    const userAgent = sanitize(params.user_agent, 500);

    if (!nome || !bairro || !avaliacao || !mensagem || aceite !== "sim") {
      return jsonResponse({
        status: "error",
        message: "Campos obrigatórios ausentes ou aceite não confirmado."
      });
    }

    const spreadsheet = getSpreadsheet();
    let sheet = spreadsheet.getSheetByName(CONFIG.SHEET_NAME);

    if (!sheet) {
      setupPlanilhaFeedback();
      sheet = spreadsheet.getSheetByName(CONFIG.SHEET_NAME);
    }

    const idResposta = Utilities.getUuid();
    const dataHora = new Date();

    sheet.appendRow([
      idResposta,
      dataHora,
      nome,
      bairro,
      avaliacao,
      mensagem,
      aceite,
      origem,
      paginaOrigem,
      userAgent
    ]);

    return jsonResponse({
      status: "success",
      message: "Feedback registrado com sucesso.",
      id_resposta: idResposta
    });

  } catch (error) {
    return jsonResponse({
      status: "error",
      message: String(error)
    });
  }
}

function sanitize(value, maxLength) {
  if (value === undefined || value === null) {
    return "";
  }

  return String(value)
    .trim()
    .replace(/\s+/g, " ")
    .substring(0, maxLength);
}

function jsonResponse(payload) {
  return ContentService
    .createTextOutput(JSON.stringify(payload))
    .setMimeType(ContentService.MimeType.JSON);
}
